// Profile.js
import React from "react";

export default function Profile() {
  return (
    <div className="flex flex-col gap-12 px-8 py-6 max-w-[1120px] w-full mx-auto">

      {/* Các mục setting */}
      <div className="flex flex-col gap-4">
        <div className="bg-[#C6E1FF85] py-3 px-6 rounded-md hover:bg-[#B0D9FF] cursor-pointer">
          <span className="text-black font-bold text-base">Đổi mật khẩu</span>
        </div>
        <div className="bg-[#C6E1FF85] py-3 px-6 rounded-md hover:bg-[#B0D9FF] cursor-pointer">
          <span className="text-black font-bold text-base">Thông báo</span>
        </div>
        <div className="bg-[#C6E1FF85] py-3 px-6 rounded-md hover:bg-[#B0D9FF] cursor-pointer">
          <span className="text-black font-bold text-base">Quyền riêng tư</span>
        </div>
      </div>

      {/* Nút đăng xuất */}
      <div className="flex justify-center">
        <button className="bg-[#FFDEF8CF] py-2 px-10 rounded-[20px] font-medium text-black hover:bg-[#FFD1EE]">
          Đăng xuất
        </button>
      </div>
    </div>
  );
}
